    15→package mvcc
    16→
    17→import (
    18→	"context"
    19→	"fmt"
    20→
    21→	"go.uber.org/zap"
    22→
    23→	"go.etcd.io/etcd/api/v3/mvccpb"
    24→	"go.etcd.io/etcd/pkg/v3/traceutil"
    25→	"go.etcd.io/etcd/server/v3/lease"
    26→	"go.etcd.io/etcd/server/v3/storage/backend"
    27→	"go.etcd.io/etcd/server/v3/storage/schema"
    28→)
    29→
    30→type storeTxnRead struct {
    31→	storeTxnCommon
    32→	tx backend.ReadTx
    33→}
    34→
    35→type storeTxnCommon struct {
    36→	s  *store
    37→	tx backend.UnsafeReader
    38→
    39→	firstRev int64
    40→	rev      int64
    41→
    42→	trace *traceutil.Trace
    43→}
    44→
    45→func (s *store) Read(mode ReadTxMode, trace *traceutil.Trace) TxnRead {
    46→	s.mu.RLock()
    47→	s.revMu.RLock()
    48→	// For read-only workloads, we use shared buffer by copying transaction read buffer
    49→	// for higher concurrency with ongoing blocking writes.
    50→	// For write/write-read transactions, we use the shared buffer
    51→	// rather than duplicating transaction read buffer to avoid transaction overhead.
    52→	var tx backend.ReadTx
    53→	if mode == ConcurrentReadTxMode {
    54→		tx = s.b.ConcurrentReadTx()
    55→	} else {
    56→		tx = s.b.ReadTx()
    57→	}
    58→
    59→	tx.RLock() // RLock is no-op. concurrentReadTx does not need to be locked after it is created.
    60→	firstRev, rev := s.compactMainRev, s.currentRev
    61→	s.revMu.RUnlock()
    62→	return newMetricsTxnRead(&storeTxnRead{storeTxnCommon{s, tx, firstRev, rev, trace}, tx})
    63→}
    64→
    65→func (tr *storeTxnCommon) FirstRev() int64 { return tr.firstRev }
    66→func (tr *storeTxnCommon) Rev() int64      { return tr.rev }
    67→
    68→func (tr *storeTxnCommon) Range(ctx context.Context, key, end []byte, ro RangeOptions) (r *RangeResult, err error) {
    69→	return tr.rangeKeys(ctx, key, end, tr.Rev(), ro)
    70→}
    71→
    72→func (tr *storeTxnCommon) rangeKeys(ctx context.Context, key, end []byte, curRev int64, ro RangeOptions) (*RangeResult, error) {
    73→	rev := ro.Rev
    74→	if rev > curRev {
    75→		return &RangeResult{KVs: nil, Count: -1, Rev: curRev}, ErrFutureRev
    76→	}
    77→	if rev <= 0 {
    78→		rev = curRev
    79→	}
    80→	if rev < tr.s.compactMainRev {
    81→		return &RangeResult{KVs: nil, Count: -1, Rev: 0}, ErrCompacted
    82→	}
    83→	if ro.Count {
    84→		total := tr.s.kvindex.CountRevisions(key, end, rev)
    85→		tr.trace.Step("count revisions from in-memory index tree")
    86→		return &RangeResult{KVs: nil, Count: total, Rev: curRev}, nil
    87→	}
    88→	revpairs, total := tr.s.kvindex.Revisions(key, end, rev, int(ro.Limit))
    89→	tr.trace.Step("range keys from in-memory index tree")
    90→	if len(revpairs) == 0 {
    91→		return &RangeResult{KVs: nil, Count: total, Rev: curRev}, nil
    92→	}
    93→
    94→	limit := int(ro.Limit)
    95→	if limit <= 0 || limit > len(revpairs) {
    96→		limit = len(revpairs)
    97→	}
    98→
    99→	kvs := make([]mvccpb.KeyValue, limit)
   100→	revBytes := NewRevBytes()
   101→	for i, revpair := range revpairs[:len(kvs)] {
   102→		select {
   103→		case <-ctx.Done():
   104→			return nil, fmt.Errorf("rangeKeys: context cancelled: %w", ctx.Err())
   105→		default:
   106→		}
   107→		revBytes = RevToBytes(revpair, revBytes)
   108→		_, vs := tr.tx.UnsafeRange(schema.Key, revBytes, nil, 0)
   109→		if len(vs) != 1 {
   110→			tr.s.lg.Fatal(
   111→				"range failed to find revision pair",
   112→				zap.Int64("revision-main", revpair.Main),
   113→				zap.Int64("revision-sub", revpair.Sub),
   114→				zap.Int64("revision-current", curRev),
   115→				zap.Int64("range-option-rev", ro.Rev),
   116→				zap.Int64("range-option-limit", ro.Limit),
   117→				zap.Binary("key", key),
   118→				zap.Binary("end", end),
   119→				zap.Int("len-revpairs", len(revpairs)),
   120→				zap.Int("len-values", len(vs)),
   121→			)
   122→		}
   123→		if err := kvs[i].Unmarshal(vs[0]); err != nil {
   124→			tr.s.lg.Fatal(
   125→				"failed to unmarshal mvccpb.KeyValue",
   126→				zap.Error(err),
   127→			)
   128→		}
   129→	}
   130→	tr.trace.Step("range keys from bolt db")
   131→	return &RangeResult{KVs: kvs, Count: total, Rev: curRev}, nil
   132→}
   133→
   134→func (tr *storeTxnRead) End() {
   135→	tr.tx.RUnlock() // RUnlock signals the end of concurrentReadTx.
   136→	tr.s.mu.RUnlock()
   137→}
   138→
   139→type storeTxnWrite struct {
   140→	storeTxnCommon
   141→	tx backend.BatchTx
   142→	// beginRev is the revision where the txn begins; it will write to the next revision.
   143→	beginRev int64
   144→	changes  []mvccpb.KeyValue
   145→}
   146→
   147→func (s *store) Write(trace *traceutil.Trace) TxnWrite {
   148→	s.mu.RLock()
   149→	tx := s.b.BatchTx()
   150→	tx.LockInsideApply()
   151→	tw := &storeTxnWrite{
   152→		storeTxnCommon: storeTxnCommon{s, tx, 0, 0, trace},
   153→		tx:             tx,
   154→		beginRev:       s.currentRev,
   155→		changes:        make([]mvccpb.KeyValue, 0, 4),
   156→	}
   157→	return newMetricsTxnWrite(tw)
   158→}
   159→
   160→func (tw *storeTxnWrite) Rev() int64 { return tw.beginRev }
   161→
   162→func (tw *storeTxnWrite) Range(ctx context.Context, key, end []byte, ro RangeOptions) (r *RangeResult, err error) {
   163→	rev := tw.beginRev
   164→	if len(tw.changes) > 0 {
   165→		rev++
   166→	}
   167→	return tw.rangeKeys(ctx, key, end, rev, ro)
   168→}
   169→
   170→func (tw *storeTxnWrite) DeleteRange(key, end []byte) (int64, int64) {
   171→	if n := tw.deleteRange(key, end); n != 0 || len(tw.changes) > 0 {
   172→		return n, tw.beginRev + 1
   173→	}
   174→	return 0, tw.beginRev
   175→}
   176→
   177→func (tw *storeTxnWrite) Put(key, value []byte, lease lease.LeaseID) int64 {
   178→	tw.put(key, value, lease)
   179→	return tw.beginRev + 1
   180→}
   181→
   182→func (tw *storeTxnWrite) End() {
   183→	// only update index if the txn modifies the mvcc state.
   184→	if len(tw.changes) != 0 {
   185→		// hold revMu lock to prevent new read txns from opening until writeback.
   186→		tw.s.revMu.Lock()
   187→		tw.s.currentRev++
   188→	}
   189→	tw.tx.Unlock()
   190→	if len(tw.changes) != 0 {
   191→		tw.s.revMu.Unlock()
   192→	}
   193→	tw.s.mu.RUnlock()
   194→}
   195→
   196→func (tw *storeTxnWrite) put(key, value []byte, leaseID lease.LeaseID) {
   197→	rev := tw.beginRev + 1
   198→	c := rev
   199→	oldLease := lease.NoLease
   200→
   201→	// if the key exists before, use its previous created and
   202→	// get its previous leaseID
   203→	_, created, ver, err := tw.s.kvindex.Get(key, rev)
   204→	if err == nil {
   205→		c = created.Main
   206→		oldLease = tw.s.le.GetLease(lease.LeaseItem{Key: string(key)})
   207→		tw.trace.Step("get key's previous created_revision and leaseID")
   208→	}
   209→	ibytes := NewRevBytes()
   210→	idxRev := Revision{Main: rev, Sub: int64(len(tw.changes))}
   211→	ibytes = RevToBytes(idxRev, ibytes)
   212→
   213→	ver = ver + 1
   214→	kv := mvccpb.KeyValue{
   215→		Key:            key,
   216→		Value:          value,
   217→		CreateRevision: c,
   218→		ModRevision:    rev,
   219→		Version:        ver,
   220→		Lease:          int64(leaseID),
   221→	}
   222→
   223→	d, err := kv.Marshal()
   224→	if err != nil {
   225→		tw.storeTxnCommon.s.lg.Fatal(
   226→			"failed to marshal mvccpb.KeyValue",
   227→			zap.Error(err),
   228→		)
   229→	}
   230→
   231→	tw.trace.Step("marshal mvccpb.KeyValue")
   232→	tw.tx.UnsafeSeqPut(schema.Key, ibytes, d)
   233→	tw.s.kvindex.Put(key, idxRev)
   234→	tw.changes = append(tw.changes, kv)
   235→	tw.trace.Step("store kv pair into bolt db")
   236→
   237→	if oldLease == leaseID {
   238→		tw.trace.Step("attach lease to kv pair")
   239→		return
   240→	}
   241→
   242→	if oldLease != lease.NoLease {
   243→		if tw.s.le == nil {
   244→			panic("no lessor to detach lease")
   245→		}
   246→		err = tw.s.le.Detach(oldLease, []lease.LeaseItem{{Key: string(key)}})
   247→		if err != nil {
   248→			tw.storeTxnCommon.s.lg.Error(
   249→				"failed to detach old lease from a key",
   250→				zap.Error(err),
   251→			)
   252→		}
   253→	}
   254→	if leaseID != lease.NoLease {
   255→		if tw.s.le == nil {
   256→			panic("no lessor to attach lease")
   257→		}
   258→		err = tw.s.le.Attach(leaseID, []lease.LeaseItem{{Key: string(key)}})
   259→		if err != nil {
   260→			panic("unexpected error from lease Attach")
   261→		}
   262→	}
   263→	tw.trace.Step("attach lease to kv pair")
   264→}
   265→
   266→func (tw *storeTxnWrite) deleteRange(key, end []byte) int64 {
   267→	rrev := tw.beginRev
   268→	if len(tw.changes) > 0 {
   269→		rrev++
   270→	}
   271→	keys, _ := tw.s.kvindex.Range(key, end, rrev)
   272→	if len(keys) == 0 {
   273→		return 0
   274→	}
   275→	for _, key := range keys {
   276→		tw.delete(key)
   277→	}
   278→	return int64(len(keys))
   279→}
   280→
   281→func (tw *storeTxnWrite) delete(key []byte) {
   282→	ibytes := NewRevBytes()
   283→	idxRev := newBucketKey(tw.beginRev+1, int64(len(tw.changes)), true)
   284→	ibytes = BucketKeyToBytes(idxRev, ibytes)
   285→
   286→	kv := mvccpb.KeyValue{Key: key}
   287→
   288→	d, err := kv.Marshal()
   289→	if err != nil {
   290→		tw.storeTxnCommon.s.lg.Fatal(
   291→			"failed to marshal mvccpb.KeyValue",
   292→			zap.Error(err),
   293→		)
   294→	}
   295→
   296→	tw.tx.UnsafeSeqPut(schema.Key, ibytes, d)
   297→	err = tw.s.kvindex.Tombstone(key, idxRev.Revision)
   298→	if err != nil {
   299→		tw.storeTxnCommon.s.lg.Fatal(
   300→			"failed to tombstone an existing key",
   301→			zap.String("key", string(key)),
   302→			zap.Error(err),
   303→		)
   304→	}
   305→	tw.changes = append(tw.changes, kv)
   306→
   307→	item := lease.LeaseItem{Key: string(key)}
   308→	leaseID := tw.s.le.GetLease(item)
   309→
   310→	if leaseID != lease.NoLease {
   311→		err = tw.s.le.Detach(leaseID, []lease.LeaseItem{item})
   312→		if err != nil {
   313→			tw.storeTxnCommon.s.lg.Error(
   314→				"failed to detach old lease from a key",
   315→				zap.Error(err),
   316→			)
   317→		}
   318→	}
   319→}
   320→
   321→func (tw *storeTxnWrite) Changes() []mvccpb.KeyValue { return tw.changes }
   322→

