   117→				zap.Binary("key", key),
   118→				zap.Binary("end", end),
   119→				zap.Int("len-revpairs", len(revpairs)),
   120→				zap.Int("len-values", len(vs)),
   121→			)
   122→		}
   123→		if err := kvs[i].Unmarshal(vs[0]); err != nil {
   124→			tr.s.lg.Fatal(
   125→				"failed to unmarshal mvccpb.KeyValue",
   126→				zap.Error(err),
   127→			)
   128→		}
   129→	}
   130→	tr.trace.Step("range keys from bolt db")
   131→	return &RangeResult{KVs: kvs, Count: total, Rev: curRev}, nil
   132→}
