   134→func (tr *storeTxnRead) End() {
   135→	tr.tx.RUnlock() // RUnlock signals the end of concurrentReadTx.
   136→	tr.s.mu.RUnlock()
   137→}
   138→
   139→type storeTxnWrite struct {
   140→	storeTxnCommon
   141→	tx backend.BatchTx
   142→	// beginRev is the revision where the txn begins; it will write to the next revision.
   143→	beginRev int64
   144→	changes  []mvccpb.KeyValue
   145→}
   146→
   147→func (s *store) Write(trace *traceutil.Trace) TxnWrite {
   148→	s.mu.RLock()
   149→	tx := s.b.BatchTx()
   150→	tx.LockInsideApply()
   151→	tw := &storeTxnWrite{
   152→		storeTxnCommon: storeTxnCommon{s, tx, 0, 0, trace},
   153→		tx:             tx,
   154→		beginRev:       s.currentRev,
   155→		changes:        make([]mvccpb.KeyValue, 0, 4),
   156→	}
   157→	return newMetricsTxnWrite(tw)
   158→}
   159→
   160→func (tw *storeTxnWrite) Rev() int64 { return tw.beginRev }
   161→
   162→func (tw *storeTxnWrite) Range(ctx context.Context, key, end []byte, ro RangeOptions) (r *RangeResult, err error) {
   163→	rev := tw.beginRev
   164→	if len(tw.changes) > 0 {
   165→		rev++
   166→	}
   167→	return tw.rangeKeys(ctx, key, end, rev, ro)
   168→}
   169→
   170→func (tw *storeTxnWrite) DeleteRange(key, end []byte) (int64, int64) {
   171→	if n := tw.deleteRange(key, end); n != 0 || len(tw.changes) > 0 {
   172→		return n, tw.beginRev + 1
   173→	}
   174→	return 0, tw.beginRev
   175→}
   176→
   177→func (tw *storeTxnWrite) Put(key, value []byte, lease lease.LeaseID) int64 {
   178→	tw.put(key, value, lease)
   179→	return tw.beginRev + 1
   180→}
   181→
   182→func (tw *storeTxnWrite) End() {
   183→	// only update index if the txn modifies the mvcc state.
   184→	if len(tw.changes) != 0 {
   185→		// hold revMu lock to prevent new read txns from opening until writeback.
   186→		tw.s.revMu.Lock()
   187→		tw.s.currentRev++
   188→	}
   189→	tw.tx.Unlock()
   190→	if len(tw.changes) != 0 {
   191→		tw.s.revMu.Unlock()
   192→	}
   193→	tw.s.mu.RUnlock()
   194→}
   195→
   196→func (tw *storeTxnWrite) put(key, value []byte, leaseID lease.LeaseID) {
   197→	rev := tw.beginRev + 1
   198→	c := rev
   199→	oldLease := lease.NoLease
   200→
   201→	// if the key exists before, use its previous created and
   202→	// get its previous leaseID
   203→	_, created, ver, err := tw.s.kvindex.Get(key, rev)
   204→	if err == nil {
   205→		c = created.Main
   206→		oldLease = tw.s.le.GetLease(lease.LeaseItem{Key: string(key)})
   207→		tw.trace.Step("get key's previous created_revision and leaseID")
   208→	}
   209→	ibytes := NewRevBytes()
   210→	idxRev := Revision{Main: rev, Sub: int64(len(tw.changes))}
   211→	ibytes = RevToBytes(idxRev, ibytes)
   212→
   213→	ver = ver + 1
   214→	kv := mvccpb.KeyValue{
   215→		Key:            key,
   216→		Value:          value,
   217→		CreateRevision: c,
   218→		ModRevision:    rev,
   219→		Version:        ver,
   220→		Lease:          int64(leaseID),
   221→	}
   222→
   223→	d, err := kv.Marshal()
   224→	if err != nil {
   225→		tw.storeTxnCommon.s.lg.Fatal(
   226→			"failed to marshal mvccpb.KeyValue",
   227→			zap.Error(err),
   228→		)
   229→	}
   230→
   231→	tw.trace.Step("marshal mvccpb.KeyValue")
